<h3>{{ $translate('names-of-your-friends') }}</h3><ol><li v-for="friend in friends"><FriendItem :name="friend.name" :surprise-friend="friend.surpriseFriend"></FriendItem></li></ol><input type="text" :value="inputText" :placeholder="$translate('add-a-friend-here')" @keyup.enter="addFriend"><button :class="{'is-active': friends.length &gt; 2}" @click="shuffleFriends">{{ $translate('shuffle-list') }}</button>